changeSet.sql:
ALTER TABLE clinlims.biorepository_approved_sample_type
ADD CONSTRAINT chk_biorepo_approved_category
CHECK (category IN ('BLOOD_DERIVED', 'NUCLEIC_ACIDS', 'TISSUE', 'CELLULAR', 'MICROBIOLOGICAL', 'OTHER'));

INSERT INTO clinlims.biorepository_approved_sample_type (id, type_of_sample_id, category, is_active, display_order, sys_user_id) SELECT nextval('clinlims.biorepository_approved_sample_type_seq'), id, 'BLOOD_DERIVED', true, 1, '1' FROM clinlims.type_of_sample WHERE LOWER(description) = 'serum' AND is_active = 'Y' LIMIT 1;
INSERT INTO clinlims.biorepository_approved_sample_type (id, type_of_sample_id, category, is_active, display_order, sys_user_id) SELECT nextval('clinlims.biorepository_approved_sample_type_seq'), id, 'BLOOD_DERIVED', true, 2, '1' FROM clinlims.type_of_sample WHERE LOWER(description) = 'plasma' AND is_active = 'Y' LIMIT 1;
INSERT INTO clinlims.biorepository_approved_sample_type (id, type_of_sample_id, category, is_active, display_order, sys_user_id) SELECT nextval('clinlims.biorepository_approved_sample_type_seq'), id, 'BLOOD_DERIVED', true, 3, '1' FROM clinlims.type_of_sample WHERE LOWER(description) LIKE '%whole blood%' AND is_active = 'Y' LIMIT 1;
-- Nucleic Acids INSERT INTO clinlims.biorepository_approved_sample_type (id, type_of_sample_id, category, is_active, display_order, sys_user_id) SELECT nextval('clinlims.biorepository_approved_sample_type_seq'), id, 'NUCLEIC_ACIDS', true, 10, '1' FROM clinlims.type_of_sample WHERE LOWER(description) = 'dna' AND is_active = 'Y' LIMIT 1;
INSERT INTO clinlims.biorepository_approved_sample_type (id, type_of_sample_id, category, is_active, display_order, sys_user_id) SELECT nextval('clinlims.biorepository_approved_sample_type_seq'), id, 'NUCLEIC_ACIDS', true, 11, '1' FROM clinlims.type_of_sample WHERE LOWER(description) = 'rna' AND is_active = 'Y' LIMIT 1;
-- Tissue samples INSERT INTO clinlims.biorepository_approved_sample_type (id, type_of_sample_id, category, is_active, display_order, sys_user_id) SELECT nextval('clinlims.biorepository_approved_sample_type_seq'), id, 'TISSUE', true, 20, '1' FROM clinlims.type_of_sample WHERE LOWER(description) LIKE '%biopsy%' OR LOWER(description) LIKE '%biopsies%' AND is_active = 'Y' LIMIT 1;
INSERT INTO clinlims.biorepository_approved_sample_type (id, type_of_sample_id, category, is_active, display_order, sys_user_id) SELECT nextval('clinlims.biorepository_approved_sample_type_seq'), id, 'TISSUE', true, 21, '1' FROM clinlims.type_of_sample WHERE LOWER(description) LIKE '%ffpe%' AND is_active = 'Y' LIMIT 1;
-- Cellular samples INSERT INTO clinlims.biorepository_approved_sample_type (id, type_of_sample_id, category, is_active, display_order, sys_user_id) SELECT nextval('clinlims.biorepository_approved_sample_type_seq'), id, 'CELLULAR', true, 30, '1' FROM clinlims.type_of_sample WHERE LOWER(description) LIKE '%cell line%' AND is_active = 'Y' LIMIT 1;
INSERT INTO clinlims.biorepository_approved_sample_type (id, type_of_sample_id, category, is_active, display_order, sys_user_id) SELECT nextval('clinlims.biorepository_approved_sample_type_seq'), id, 'CELLULAR', true, 31, '1' FROM clinlims.type_of_sample WHERE LOWER(description) LIKE '%pbmc%' AND is_active = 'Y' LIMIT 1;
-- Microbiological samples INSERT INTO clinlims.biorepository_approved_sample_type (id, type_of_sample_id, category, is_active, display_order, sys_user_id) SELECT nextval('clinlims.biorepository_approved_sample_type_seq'), id, 'MICROBIOLOGICAL', true, 40, '1' FROM clinlims.type_of_sample WHERE LOWER(description) LIKE '%isolate%' AND is_active = 'Y' LIMIT 1;
INSERT INTO clinlims.biorepository_approved_sample_type (id, type_of_sample_id, category, is_active, display_order, sys_user_id) SELECT nextval('clinlims.biorepository_approved_sample_type_seq'), id, 'MICROBIOLOGICAL', true, 41, '1' FROM clinlims.type_of_sample WHERE LOWER(description) LIKE '%culture%' AND is_active = 'Y' LIMIT 1;
